// --- Mocks & Helpers ---------------------------------------------------------

// Simulate dice roll (2d6). For deterministic tests, we can override.
const rollDice = (override = null) => override || (Math.floor(Math.random() * 6) + 1) + (Math.floor(Math.random() * 6) + 1);

// Tile types
const TileType = { ELEMENTAL: 'elemental', EMPTY: 'empty', SAFE_ZONE: 'safe', START: 'start', FINAL_GOAL: 'final_goal' };

// Elements
const Element = { FIRE: 'fire', ICE: 'ice', GRASS: 'grass', ROCK: 'rock' };

// Characters default (Pillow base)
const DEFAULT_CHARACTER = {
  affinity: Element.FIRE,
  atk: 30,
  mag: 10,
  hp: 1000,
  comboRewards: {
    tier1: 'power_surge', // +150 ATK all tokens
    tier2: 'double_harvest', // tileGainMultiplier ×2
    tier3: 'absolute_might' // ATK ×1.5 round up
  }
};

// Game state factory (per player)
const createPlayerState = (character = DEFAULT_CHARACTER, startTileId) => ({
  character,
  hp: character.hp,
  mag: 0,
  elementAffinity: character.affinity,
  elementQueue: [],
  comboCount: 0,
  tileGainMultiplier: 1,
  doubleRollCooldown: 0, // rounds remaining
  consecutiveRollsThisTurn: 0,
  ultimateExtraRolls: 0,
  emptyTileVisits: 0,
  kickCount: 0,
  tokens: [] // will be populated with token objects
});

// Token factory
const createToken = (position, atk = 0, frozenRounds = 0) => ({
  position,
  atk,
  frozenRounds
});

// Board setup helper — minimal representation for tests
const createBoard = (tiles = []) => ({
  tiles, // array of { id, type, element?, isSafeZone? }
  getTile: function(id) { return this.tiles.find(t => t.id === id); },
  getPath: function(fromId, steps) {
    // Simplified: linear path; full game has branch logic
    let pos = fromId;
    for (let i = 0; i < steps; i++) {
      pos = (pos + 1) % this.tiles.length;
    }
    return pos;
  }
});

// --- Core Mechanics Tests ----------------------------------------------------

describe('Elemental Hunter — Core Mechanics', () => {

  describe('Token movement', () => {
    test('Token moves exact number of steps (dice sum)', () => {
      const board = createBoard([{id:0, type:TileType.START, isSafeZone:true}, {id:1}, {id:2}, {id:3}]);
      const player = createPlayerState(DEFAULT_CHARACTER, 0);
      const token = createToken(0);
      player.tokens = [token];

      // Simulate move 4 steps
      const steps = 4;
      token.position = board.getPath(token.position, steps);

      expect(token.position).toBe(4 % board.tiles.length);
    });

    test('Token stops at Final Goal if steps exceed', () => {
      const board = createBoard([
        {id:0}, {id:1}, {id:2}, {id:3}, {id:4}, {id:5}, {id:6}, {id:7}, {id:8}, {id:9}, {id:10, type:TileType.FINAL_GOAL}
      ]);
      const player = createPlayerState(DEFAULT_CHARACTER, 0);
      const token = createToken(9); // one before final goal
      player.tokens = [token];

      const steps = 5; // would overshoot
      token.position = board.getPath(token.position, steps);

      // Rule: dừng tại Final Goal nếu vượt qua
      expect(token.position).toBe(10);
    });

    test('Frozen token cannot be selected for movement', () => {
      const player = createPlayerState(DEFAULT_CHARACTER, 0);
      const token = createToken(0, 0, 2); // frozenRounds = 2
      player.tokens = [token];

      // Selection logic should filter out frozen tokens
      const selectable = player.tokens.filter(t => t.frozenRounds === 0);
      expect(selectable).toHaveLength(0);
    });
  });

  describe('Element collection', () => {
    test('Token gains +ATK when landing on Elemental tile with element == Affinity', () => {
      const player = createPlayerState({...DEFAULT_CHARACTER, affinity: Element.FIRE}, 0);
      const token = createToken(0);
      player.tokens = [token];
      const tile = { type: TileType.ELEMENTAL, element: Element.FIRE };

      // Simulate landing
      if (tile.element === player.elementAffinity) {
        token.atk += player.character.atk * player.tileGainMultiplier;
      }

      expect(token.atk).toBe(30);
    });

    test('Player gains +MAG when landing on Elemental tile with element != Affinity', () => {
      const player = createPlayerState({...DEFAULT_CHARACTER, affinity: Element.FIRE}, 0);
      const token = createToken(0);
      player.tokens = [token];
      const tile = { type: TileType.ELEMENTAL, element: Element.ICE };

      if (tile.element !== player.elementAffinity) {
        player.mag += player.character.mag * player.tileGainMultiplier;
      }

      expect(player.mag).toBe(10);
    });

    test('Element added to end of queue, full queue removes oldest', () => {
      const player = createPlayerState();
      player.elementQueue = [Element.FIRE, Element.ICE]; // size 2, max 3

      const maxQueue = 3;
      player.elementQueue.push(Element.GRASS);
      if (player.elementQueue.length > maxQueue) {
        player.elementQueue.shift(); // remove oldest
      }

      expect(player.elementQueue).toEqual([Element.ICE, Element.GRASS]);
    });

    test('Game start adds 1 Affinity element to head of queue', () => {
      const player = createPlayerState({...DEFAULT_CHARACTER, affinity: Element.ICE});
      // At match start:
      player.elementQueue.unshift(player.elementAffinity);

      expect(player.elementQueue[0]).toBe(Element.ICE);
    });
  });

  describe('Power Roll', () => {
    test('Power Roll has 20% chance to land in target range (statistical approximation)', () => {
      // This is a statistical property; we test the logic that given a target range,
      // the outcome either matches or not. The 20% is a balance constant.
      // For unit test, we verify that target range check works.
      const targetMin = 5, targetMax = 7;
      const roll = 6;
      expect(roll >= targetMin && roll <= targetMax).toBe(true);
    });

    test('Power Roll without target range selection should be ignored', () => {
      const actionTaken = true;
      const targetRangeSelected = false;

      // If targetRangeSelected == false, the dice roll action is ignored
      const shouldProceed = targetRangeSelected;
      expect(shouldProceed).toBe(false);
    });
  });

  describe('Roll Double & Consecutive Roll Cap', () => {
    test('Rolling doubles grants an extra turn', () => {
      const player = { consecutiveRollsThisTurn: 0, ultimateExtraRolls: 0 };
      const dice = [4,4]; // double

      if (dice[0] === dice[1]) {
        player.ultimateExtraRolls++; // extra turn token
      }
      expect(player.ultimateExtraRolls).toBe(1);
    });

    test('After double roll, doubleRollCooldown set to 2 rounds', () => {
      const player = { doubleRollCooldown: 0 };
      // On double:
      player.doubleRollCooldown = 2;
      expect(player.doubleRollCooldown).toBe(2);
    });

    test('When consecutiveRollsThisTurn >= MAX_CONSECUTIVE_ROLLS, no extra turn from Roll Double', () => {
      const player = { consecutiveRollsThisTurn: 3, ultimateExtraRolls: 1 };
      const dice = [5,5]; // double rolled but cap reached

      if (player.consecutiveRollsThisTurn < 3 && dice[0] === dice[1]) {
        player.ultimateExtraRolls++;
      }

      expect(player.ultimateExtraRolls).toBe(1); // unchanged
    });

    test('Roll Double during cooldown does not grant extra turn', () => {
      const player = { doubleRollCooldown: 1, consecutiveRollsThisTurn: 0, ultimateExtraRolls: 0 };
      const dice = [6,6];

      if (player.doubleRollCooldown > 0) {
        // cooldown active, still count as double but no extra turn
        // do not increment ultimateExtraRolls
      } else if (dice[0] === dice[1]) {
        player.ultimateExtraRolls++;
      }
      expect(player.ultimateExtraRolls).toBe(0);
    });
  });

  describe('Combo system (C3 and C4)', () => {
    test('C3 (Triple Threat) triggers with 3 consecutive identical elements', () => {
      const queue = [Element.FIRE, Element.FIRE, Element.FIRE];
      const comboTriggered = (() => {
        let i = 0;
        while (i < queue.length - 2) {
          if (queue[i] === queue[i+1] && queue[i+1] === queue[i+2]) return true;
          i++;
        }
        return false;
      })();
      expect(comboTriggered).toBe(true);
    });

    test('C4 (Elemental Master) triggers with 4 consecutive different elements', () => {
      const queue = [Element.FIRE, Element.ICE, Element.GRASS, Element.ROCK];
      const allDifferent = new Set(queue).size === 4;
      expect(allDifferent).toBe(true);
    });

    test('C3 has priority over C4 when both could trigger', () => {
      // Example: queue = [FIRE, FIRE, FIRE, ICE]
      // GDD states C3 priority
      const queue = [Element.FIRE, Element.FIRE, Element.FIRE, Element.ICE];
      // Find first C3 from left
      let foundC3 = false;
      for (let i = 0; i < queue.length - 2; i++) {
        if (queue[i] === queue[i+1] && queue[i+1] === queue[i+2]) {
          foundC3 = true;
          break;
        }
      }
      expect(foundC3).toBe(true);
    });

    test('Combon removes triggering elements from queue', () => {
      let queue = [Element.FIRE, Element.FIRE, Element.FIRE, Element.ICE];
      // C3 at indices 0-2, remove them
      queue.splice(0, 3);
      expect(queue).toEqual([Element.ICE]);
    });

    test('Combo applies Tier 1 reward (+150 ATK to all tokens)', () => {
      const player = { tokens: [{atk:10}, {atk:20}, {atk:30}] };
      // Apply Tier 1
      player.tokens.forEach(t => t.atk += 150);
      expect(player.tokens[0].atk).toBe(160);
      expect(player.tokens[1].atk).toBe(170);
      expect(player.tokens[2].atk).toBe(180);
    });

    test('Tier 2 (Double Harvest) sets tileGainMultiplier to ×2 at milestone 2', () => {
      const player = { tileGainMultiplier: 1, comboCount: 1 };
      // After second combo:
      player.comboCount = 2;
      if (player.comboCount >= 2) {
        player.tileGainMultiplier = 2;
      }
      expect(player.tileGainMultiplier).toBe(2);
    });

    test('Tier 3 (Absolute Might) multiplies all tokens ATK by 1.5 (round up) at milestone 3', () => {
      const player = { tokens: [{atk: 10}, {atk: 11}], comboCount: 2 };
      // After third combo:
      player.comboCount = 3;
      if (player.comboCount >= 3) {
        player.tokens.forEach(t => t.atk = Math.ceil(t.atk * 1.5));
      }
      expect(player.tokens[0].atk).toBe(15);
      expect(player.tokens[1].atk).toBe(17); // 11*1.5 = 16.5 → ceil 17
    });

    test('Combo count resets to 0 at end of match', () => {
      const player = { comboCount: 5 };
      // At end of match
      player.comboCount = 0;
      expect(player.comboCount).toBe(0);
    });
  });

  describe('Kick mechanic', () => {
    test('Kick deals damage equal to ATK of kicking token', () => {
      const defender = { hp: 1000 };
      const attackerTokenAtk = 50;
      defender.hp -= attackerTokenAtk;
      expect(defender.hp).toBe(950);
    });

    test('Kicked token is pushed back to nearest Safe Zone behind (along its movement direction)', () => {
      // Simplified: board tiles 0-10; token at pos 5 moving clockwise; nearest safe zone behind is pos 0
      const findSafeZoneBehind = (pos, direction = 1, board) => {
        // search backward (counter-direction) until safe zone found
        let check = pos - 1;
        while (check >= 0) {
          const tile = board.getTile(check);
          if (tile && tile.isSafeZone) return check;
          check--;
        }
        return 0; // fallback
      };
      const board = createBoard([
        {id:0, type:TileType.SAFE_ZONE, isSafeZone:true},
        {id:1},
        {id:2},
        {id:3},
        {id:4},
        {id:5}
      ]);
      const newPos = findSafeZoneBehind(5, 1, board);
      expect(newPos).toBe(0);
    });

    test('Kick increments kickCount of attacker by 1', () => {
      const player = { kickCount: 0 };
      player.kickCount++;
      expect(player.kickCount).toBe(1);
    });

    test('If ATK = 0, kick still pushes but no damage', () => {
      const defender = { hp: 500 };
      const attackerAtk = 0;
      // damage
      defender.hp -= attackerAtk;
      // push logic happens regardless
      expect(defender.hp).toBe(500);
    });

    test('Kick does NOT occur if landing tile is Safe Zone', () => {
      const tile = { type: TileType.SAFE_ZONE, isSafeZone: true };
      const shouldKick = !tile.isSafeZone;
      expect(shouldKick).toBe(false);
    });
  });

  describe('HP and KO', () => {
    test('Player HP starts at character.hp', () => {
      const player = createPlayerState(DEFAULT_CHARACTER, 0);
      expect(player.hp).toBe(1000);
    });

    test('HP decreases only from Kick or Goal token attack (verify via Kick test)', () => {
      // This is a system rule; Kick test covers damage application
      const player = { hp: 1000 };
      player.hp -= 30; // simulate kick
      expect(player.hp).toBe(970);
    });

    test('If HP ≤ 0, player KO and opponent wins immediately', () => {
      const playerHP = -5;
      const isKO = playerHP <= 0;
      expect(isKO).toBe(true);
    });
  });

  describe('MAG and Ultimate', () => {
    test('MAG increases when landing on element != Affinity', () => {
      const player = createPlayerState({...DEFAULT_CHARACTER, affinity: Element.FIRE}, 0);
      const tileElement = Element.ICE;
      if (tileElement !== player.elementAffinity) {
        player.mag += player.character.mag * player.tileGainMultiplier;
      }
      expect(player.mag).toBe(10);
    });

    test('MAG is capped by magCap (if defined)', () => {
      const magCap = 100;
      const player = { mag: 95 };
      player.mag = Math.min(player.mag + 10, magCap);
      expect(player.mag).toBe(100);
    });

    test('Ultimate costs 50 MAG', () => {
      const player = { mag: 70 };
      const ULTIMATE_COST = 50;
      const canActivate = player.mag >= ULTIMATE_COST;
      if (canActivate) {
        player.mag -= ULTIMATE_COST;
        player.ultimateExtraRolls++;
      }
      expect(player.mag).toBe(20);
      expect(player.ultimateExtraRolls).toBe(1);
    });

    test('If consecutiveRollsThisTurn >= MAX_CONSECUTIVE_ROLLS, Ultimate cannot be activated', () => {
      const player = { consecutiveRollsThisTurn: 3, mag: 60, ultimateExtraRolls: 0 };
      const MAX_CONSECUTIVE_ROLLS = 3;
      const canActivate = player.mag >= 50 && player.consecutiveRollsThisTurn < MAX_CONSECUTIVE_ROLLS;
      if (canActivate) {
        player.mag -= 50;
        player.ultimateExtraRolls++;
      }
      expect(player.ultimateExtraRolls).toBe(0); // blocked by cap
    });
  });

  describe('Artifacts (Empty Tile)', () => {
    test('Landing on Empty Tile triggers artifact selection', () => {
      const tile = { type: TileType.EMPTY };
      const isArtifactTile = tile.type === TileType.EMPTY;
      expect(isArtifactTile).toBe(true);
    });

    test('Artifact Swap unlocked at emptyTileVisits ≥ 1', () => {
      const visits = 1;
      const canSwap = visits >= 1;
      expect(canSwap).toBe(true);
    });

    test('Artifact Change unlocked at emptyTileVisits ≥ 2', () => {
      const visits = 2;
      const canChange = visits >= 2;
      expect(canChange).toBe(true);
    });

    test('Artifact Charge unlocked at emptyTileVisits ≥ 3', () => {
      const visits = 3;
      const canCharge = visits >= 3;
      expect(canCharge).toBe(true);
    });

    test('Swap exchanges 2 adjacent elements in queue', () => {
      const queue = [Element.FIRE, Element.ICE, Element.GRASS];
      // Swap indices 0 and 1
      [queue[0], queue[1]] = [queue[1], queue[0]];
      expect(queue).toEqual([Element.ICE, Element.FIRE, Element.GRASS]);
    });

    test('Change converts one element to another type', () => {
      const queue = [Element.FIRE, Element.ICE];
      const changeIndex = 0;
      const newElement = Element.ROCK;
      queue[changeIndex] = newElement;
      expect(queue).toEqual([Element.ROCK, Element.ICE]);
    });

    test('Charge adds 1 Affinity element to end of queue', () => {
      const player = { elementAffinity: Element.GRASS, elementQueue: [Element.FIRE] };
      player.elementQueue.push(player.elementAffinity);
      expect(player.elementQueue).toEqual([Element.FIRE, Element.GRASS]);
    });

    test('Swap with <2 elements in queue has no effect (artifact ignored)', () => {
      const queue = [Element.FIRE]; // size 1
      const originalQueue = [...queue];
      if (queue.length < 2) {
        // Swap ignored; no change
      }
      expect(queue).toEqual(originalQueue);
    });
  });

  describe('Level settings', () => {
    test('Level 1: maxRounds 12, Tier 1, slots 1', () => {
      const config = { maxRounds: 12, maxComboTier: 1, artifactSlots: 1 };
      expect(config.maxRounds).toBe(12);
      expect(config.maxComboTier).toBe(1);
      expect(config.artifactSlots).toBe(1);
    });

    test('Level 2: maxRounds 15, Tier 2, slots 2', () => {
      const config = { maxRounds: 15, maxComboTier: 2, artifactSlots: 2 };
      expect(config.maxRounds).toBe(15);
      expect(config.maxComboTier).toBe(2);
      expect(config.artifactSlots).toBe(2);
    });

    test('Level 3: maxRounds 15, Tier 3, slots 3', () => {
      const config = { maxRounds: 15, maxComboTier: 3, artifactSlots: 3 };
      expect(config.maxRounds).toBe(15);
      expect(config.maxComboTier).toBe(3);
      expect(config.artifactSlots).toBe(3);
    });
  });

});

// --- Edge Cases (GDD Section 4) ----------------------------------------------

describe('Elemental Hunter — Edge Cases', () => {

  test('Edge case: Full queue overflow — adding new element removes oldest', () => {
    const maxQueue = 3;
    const queue = [Element.FIRE, Element.ICE, Element.GRASS];
    // Add new
    queue.push(Element.ROCK);
    if (queue.length > maxQueue) {
      queue.shift();
    }
    expect(queue).toEqual([Element.ICE, Element.GRASS, Element.ROCK]);
  });

  test('Edge case: Frozen token cannot be moved', () => {
    const token = { frozenRounds: 2 };
    const canMove = token.frozenRounds === 0;
    expect(canMove).toBe(false);
  });

  test('Edge case: Consecutive roll cap reached — Roll Double grants no extra turn', () => {
    const state = { consecutiveRollsThisTurn: 3, ultimateExtraRolls: 1 };
    const diceDouble = true;
    if (state.consecutiveRollsThisTurn >= 3 && diceDouble) {
      // no extra turn
    } else if (diceDouble) {
      state.ultimateExtraRolls++;
    }
    expect(state.ultimateExtraRolls).toBe(1);
  });

  test('Edge case: Swap artifact with <2 elements in queue is ignored', () => {
    const queue = [Element.FIRE];
    const original = [...queue];
    if (queue.length < 2) {
      // ignore
    }
    expect(queue).toEqual(original);
  });

  test('Edge case: Kick on Safe Zone does not occur', () => {
    const tile = { isSafeZone: true };
    const shouldKick = !tile.isSafeZone;
    expect(shouldKick).toBe(false);
  });

  test('Edge case: Multiple tokens from same player reaching Final Goal in same turn sequence; each processed independently', () => {
    const player = { tokens: [{atk:10}, {atk:20}], elementQueue: [] };
    const applyGoalReward = (token) => {
      // Add element to queue end
      player.elementQueue.push(Element.FIRE);
      // Token returns to Safe Zone (position reset; skip for logic test)
    };
    player.tokens.forEach(applyGoalReward);
    expect(player.elementQueue).toEqual([Element.FIRE, Element.FIRE]);
  });

  test('Edge case: Roll Double during doubleRollCooldown — no extra turn', () => {
    const state = { doubleRollCooldown: 1, consecutiveRollsThisTurn: 0 };
    const dice = [3,3];
    if (state.doubleRollCooldown > 0) {
      // count as double but no extra turn
    } else if (dice[0] === dice[1]) {
      state.consecutiveRollsThisTurn++;
    }
    expect(state.consecutiveRollsThisTurn).toBe(0);
  });

  test('Edge case: Power Roll without target range selection ignored', () => {
    const action = { type: 'power_roll', targetSelected: false };
    const shouldProceed = action.targetSelected;
    expect(shouldProceed).toBe(false);
  });

});

// --- Win/Lose Conditions (GDD Section 3) -------------------------------------

describe('Elemental Hunter — Win/Lose Conditions', () => {

  test('Win condition: KO when opponent HP ≤ 0', () => {
    const opponentHP = -10;
    const isKO = opponentHP <= 0;
    expect(isKO).toBe(true);
  });

  test('Win condition: Round limit reached, higher HP wins', () => {
    const p1HP = 800;
    const p2HP = 750;
    const p1Wins = p1HP > p2HP;
    expect(p1Wins).toBe(true);
  });

  test('Tie-break: HP equal → Player2 wins (Last Mover Advantage)', () => {
    const p1HP = 600;
    const p2HP = 600;
    let winner;
    if (p1HP > p2HP) winner = 1;
    else if (p2HP > p1HP) winner = 2;
    else winner = 2; // tie goes to P2
    expect(winner).toBe(2);
  });

});

// --- Integration Checks -------------------------------------------------------

describe('Elemental Hunter — Integration Scenarios', () => {

  test('Scenario: Affinity element collection grants ATK, non-Affinity grants MAG', () => {
    const player = createPlayerState({...DEFAULT_CHARACTER, affinity: Element.FIRE}, 0);
    const token = createToken(0);
    player.tokens = [token];

    // Land on Fire (same)
    const tileFire = { type: TileType.ELEMENTAL, element: Element.FIRE };
    if (tileFire.element === player.elementAffinity) {
      token.atk += player.character.atk;
    }
    // Land on Ice (diff)
    const tileIce = { type: TileType.ELEMENTAL, element: Element.ICE };
    if (tileIce.element !== player.elementAffinity) {
      player.mag += player.character.mag;
    }

    expect(token.atk).toBe(30);
    expect(player.mag).toBe(10);
  });

  test('Scenario: Combo cascade after adding element to queue', () => {
    const player = { elementQueue: [Element.FIRE, Element.ICE, Element.GRASS], comboCount: 0, tokens: [{atk:0}] };
    // Add FIRE → queue = [FIRE, ICE, GRASS, FIRE]
    player.elementQueue.push(Element.FIRE);
    // Check for C4: first 4 are distinct? FIRE, ICE, GRASS, FIRE — not distinct
    // Check for C3: any 3 consecutive same? no
    // So no combo yet.
    // Instead, add another FIRE to make [FIRE, ICE, GRASS, FIRE, FIRE] — still no C3
    // To trigger C3: [A,A,A] substring. Let's manually simulate:
    player.elementQueue = [Element.FIRE, Element.FIRE, Element.FIRE];
    // C3 detected at indices 0-2
    const c3Indices = [0,1,2];
    // Remove elements
    player.elementQueue.splice(0, 3);
    // Apply Tier 1: +150 ATK
    player.tokens.forEach(t => t.atk += 150);
    player.comboCount++;

    expect(player.elementQueue).toEqual([]);
    expect(player.tokens[0].atk).toBe(150);
    expect(player.comboCount).toBe(1);
  });

});
